<template>
  <LTPages
      :title="'自定义表格列'"
      isNormal
  >
    <template v-slot:content>
      <div class="Docs-Body">
        <!--说明-->
        <div class="zhb-allnum-tip">
          <i class="icon zhb-iconfont zhb-icongantanhao"></i>
          <div style="width: 100%;">基于element封装的基础表格和分页。表格列可自定义设置进度条、固定、图片预览、icon,点击等。详情参见：tableHead配置。</div>
        </div>
        <!--1、基本用法-->
        <div class="zhb-title">基本用法</div>
        <div>
          <LTTableForm
              v-if="tableConfig.tableRefresh"
              v-loading="tableConfig.tableLoading"
              :tableConfig="tableConfig"
              @tablePageForm="getTableForm"
              @setTableCol="getTableCol"
          ></LTTableForm>
        </div>
        <!--2、代码展示-->
        <div class="zhb-title" style="margin-top: 20px;">代码展示</div>
        <!--template-->
        <codeCopy :code="mainCode" id="LTSearchForm1" title="template"></codeCopy>
        <!--javaScript-->
        <codeCopy :code="jsCode" id="LTSearchForm2" title="javaScript"></codeCopy>
        <!--5、tableHead配置参数-->
        <div class="zhb-title">tableHead配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="tableHeadData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column show-overflow-tooltip  prop="text1" label="参数"/>
            <el-table-column show-overflow-tooltip  prop="text2" label="说明"/>
            <el-table-column show-overflow-tooltip  prop="text3" label="类型"/>
            <el-table-column show-overflow-tooltip  prop="text4" label="可选值"/>
            <el-table-column show-overflow-tooltip  prop="text5" label="默认值"/>
            <el-table-column show-overflow-tooltip  prop="text6" label="备注"/>

          </el-table>
        </div>
        <!--3、配置参数-->
        <div class="zhb-title">配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="tableData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column prop="text1" label="参数"/>
            <el-table-column prop="text2" label="说明"/>
            <el-table-column prop="text3" label="类型"/>
            <el-table-column prop="text4" label="可选值"/>
            <el-table-column prop="text5" label="默认值"/>
            <el-table-column prop="text6" label="备注"/>

          </el-table>
        </div>
        <!--4、tableConfig配置参数-->
        <div class="zhb-title">tableConfig配置参数</div>
        <div style="margin-bottom: 30px;">
          <el-table
              :data="tableConfigData"
              :header-cell-style="{
                background:'#0F1F43',
                fontSize:'14px',
                color:'rgba(0,0,0,.85)'
            }">
            <el-table-column prop="text1" label="参数"/>
            <el-table-column prop="text2" label="说明"/>
            <el-table-column prop="text3" label="类型"/>
            <el-table-column prop="text4" label="可选值"/>
            <el-table-column prop="text5" label="默认值"/>
            <el-table-column prop="text6" label="备注"/>

          </el-table>
        </div>










      </div>
    </template>
  </LTPages>
</template>

<script>
export default {
  data() {
    return {
      tableConfig: {
        tableRefresh: true,
        tableLoading: false,
        tableHead: [
          {
            label: '用户名称',
            prop: 'username',
            isTemplate: true, //开启表格列点击
            color: '#13ce66', //设置表格列字体颜色,不设置默认为红色,
            ColWidth: '150'
          },
          {
            label: '是否管理员',
            prop: 'isAdmin',
            isSwitch: true,
            activeColor: '#13ce66',
            inactiveColor: '#DDDFE5',
            activeText: '是',
            inactiveText: '否',
            inlinePrompt: true,
            ColWidth: '120'
            //disabled: true,
          },
          {
            label: '图片',
            prop: 'picPath',
            isLookPic: true,
            LookPicType: true
          },
          {
            label: '事件等级',
            prop: 'alarmLevel',
            subProp: 'alarmIcon',
            isShowIcon: true,
            ColWidth: '100'
          },
          {
            label: '手机号',
            prop: 'mobile',
          },
          {
            label: '部门',
            prop: 'dept',
          },
          {
            label: '进度',
            prop: 'progress',
            isProgress: true
          },
          {
            label: '状态',
            prop: 'StatusName',
            isStatus: true, //开启表格列状态
            subProp: 'status', //子属性
            colors: {
              0: '#F56C6C',
              1: '#F7BA2A',
              2: '#5cb87a',
            }
          },
          {
            label: '创建时间',
            prop: 'createTime',
          },
        ],
        tableData: [
          {StatusName: '已激活', status: '1',alarmLevel: "1",alarmIcon: "1ji",username: "李辛",picPath: 'https://ftp.bmp.ovh/imgs/2021/06/18714484ed0bcedd.jpeg', progress:'45', isAdminName: '是', mobile: '15974856942', dept: '立图开发组', createTime: '2024-04-28 14:30'},
          {StatusName: '未激活', status: '0',alarmLevel: "2",alarmIcon: "2ji",username: "姜磊", isAdminName: '否', mobile: '18255060105', dept: '立图开发组', createTime: '2024-04-28 14:30'},
          {StatusName: '已激活', status: '1',alarmLevel: "3",alarmIcon: "3ji",username: "冒慧敏", isAdminName: '否', mobile: '18547896584', dept: '立图开发组', createTime: '2024-04-28 14:30'},
        ],
        columnButton: [],
        columnWidth: "130",
        // tableColWidth:'155',
        isHiddenSelection: true, // 是否隐藏勾选
        isHiddenIndex: true, // 是否隐藏序号
        total: 150,
        pageSize: 20,
        currentPage: 1,
      },
      mainCode: `<LTTableForm
            v-if="tableConfig.tableRefresh"
            v-loading="tableConfig.tableLoading"
            :tableConfig="tableConfig"
            @tablePageForm="getTableForm"
            @setTableCol="getTableCol"
        ></LTTableForm>`,
      jsCode: `
export default {
  data() {
    return {

      tableConfig: {
        tableRefresh: true,
        tableLoading: false,
        tableHead: [
          {
            label: '用户名称',
            prop: 'username',
            isTemplate: true, //开启表格列点击
            color: '#13ce66', //设置表格列字体颜色,不设置默认为红色,
            ColWidth: '150'
          },
          {
            label: '是否管理员',
            prop: 'isAdmin',
            isSwitch: true,
            activeColor: '#13ce66',
            inactiveColor: '#DDDFE5',
            activeText: '是',
            inactiveText: '否',
            inlinePrompt: true,
            ColWidth: '120'
            //disabled: true,
          },
          {
            label: '图片',
            prop: 'picPath',
            isLookPic: true,
            LookPicType: true
          },
          {
            label: '事件等级',
            prop: 'alarmLevel',
            subProp: 'alarmIcon',
            isShowIcon: true,
            ColWidth: '100'
          },
          {
            label: '手机号',
            prop: 'mobile',
          },
          {
            label: '部门',
            prop: 'dept',
          },
          {
            label: '进度',
            prop: 'progress',
            isProgress: true
          },
          {
            label: '状态',
            prop: 'StatusName',
            isStatus: true, //开启表格列状态
            subProp: 'status', //子属性
            colors: {
              0: '#F56C6C',
              1: '#F7BA2A',
              2: '#5cb87a',
            }
          },
          {
            label: '创建时间',
            prop: 'createTime',
          },
        ],
        tableData: [
          {StatusName: '已激活', status: '1',alarmLevel: "1",alarmIcon: "1ji",username: "李辛",picPath: 'https://ftp.bmp.ovh/imgs/2021/06/18714484ed0bcedd.jpeg', progress:'45', isAdminName: '是', mobile: '15974856942', dept: '立图开发组', createTime: '2024-04-28 14:30'},
          {StatusName: '未激活', status: '0',alarmLevel: "2",alarmIcon: "2ji",username: "姜磊", isAdminName: '否', mobile: '18255060105', dept: '立图开发组', createTime: '2024-04-28 14:30'},
          {StatusName: '已激活', status: '1',alarmLevel: "3",alarmIcon: "3ji",username: "冒慧敏", isAdminName: '否', mobile: '18547896584', dept: '立图开发组', createTime: '2024-04-28 14:30'},
        ],
        columnButton: [],
        columnWidth: "130",
        // tableColWidth:'155',
        isHiddenSelection: true, // 是否隐藏勾选
        isHiddenIndex: true, // 是否隐藏序号
        total: 150,
        pageSize: 20,
        currentPage: 1,
      }
    }
  },
  methods: {
    // 表格分页回调
    getTableForm(page) {
      this.tableConfig.pageSize = page.pageSize;
      this.tableConfig.currentPage = page.pageNum;
      this.$message.success({
        message: "这是‘分页跳转’操作",
        showClose: true,
        duration: 1000,
      });
    },
    // 表格列点击回调
    getTableCol(data) {
      this.$message.success({
        message: "这是‘表格列点击’操作",
        showClose: true,
        duration: 1000,
      });

    }
  }
}`,
      tableData: [
        {
          text1:'tableConfig',
          text2:'表格配置',
          text3:'Object',
          text4:'---',
          text5:'---',
          text6:'必填项',
        },
        {
          text1:'@tablePageForm',
          text2:'获取分页变化数据',
          text3:'Function',
          text4:'---',
          text5:'---',
          text6:'必填项',
        }
      ],
      tableHeadData: [
        {
          text1:'ColWidth',
          text2:'定义表格列宽度',
          text3:'Number',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'fixed',
          text2:'表格列是否固定',
          text3:'String',
          text4:'【left】、【right】',
          text5:'---',
          text6:'---',
        },
        {
          text1:'isProgress',
          text2:'是否显示进度条',
          text3:'Boolean',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'isTemplate',
          text2:'表格列是否可点击',
          text3:'Boolean',
          text4:'---',
          text5:'---',
          text6:"color: '#13ce66', //设置表格列字体颜色,不设置默认为红色" +
              "回调方法：@setTableCol",
        },
        {
          text1:'isLookPic',
          text2:'表格列展示图片',
          text3:'Boolean',
          text4:'---',
          text5:'false',
          text6:"LookPicType 设置true 或 false ;是图片展示的两种样式。",
        },
        {
          text1:'isSwitch',
          text2:'表格列Switch展示 操作',
          text3:'Boolean',
          text4:'---',
          text5:'---',
          text6:"\n" +
              "            activeColor: '#13ce66',// 选中颜色\n" +
              "            inactiveColor: '#DDDFE5',//关闭颜色\n" +
              "            activeText: '是',//选中文本\n" +
              "            inactiveText: '否',// 关闭文本\n" +
              "            inlinePrompt: true,// 是否可操作",
        },
        {
          text1:'isShowIcon',
          text2:'是否显示icon',
          text3:'Boolean',
          text4:'icon类型可选值：1ji、2ji、3ji、4ji、icon-play、icon-sb、icon-success、icon-error、icon-warning、' +
              'image、jpg、mp4、mv、png、pdf、ppt、txt、zip、xlsx、SXT-LX、SCT-ZX',
          text5:'---',
          text6:`
            subProp: 'deptType'(必填)，显示icon类型的字段，

            isShowIconMethod: true, //是否icon可点击
            handle: (row) => { // 回调
              console.log(row);
            }`,
        },
        {
          text1:'isStatus',
          text2:'开启表格列状态样式',
          text3:'Boolean',
          text4:'状态枚举值 必须设置0、1，例如： 0 隐藏，1 显示。',
          text5:'---',
          text6:`subProp: 'status', //子属性
            colors: {
              0: '#F56C6C',
              1: '#F7BA2A',
              2: '#5cb87a',
            },
            textColors: {
              0: '#F56C6C',
              1: '#F7BA2A',
              2: '#5cb87a',
            },`,
        },
      ],
      tableConfigData: [
        {
          text1:'tableRefresh',
          text2:'是否显示表格组件',
          text3:'Boolean',
          text4:'---',
          text5:'true',
          text6:'必填项',
        },
        {
          text1:'tableLoading',
          text2:'刷新表格组件',
          text3:'Boolean',
          text4:'---',
          text5:'false',
          text6:'---',
        },
        {
          text1:'tableHead',
          text2:'表格表头及其字段',
          text3:'Object',
          text4:'---',
          text5:'---',
          text6:'必填项',
        },
        {
          text1:'tableData',
          text2:'表格数据',
          text3:'Object',
          text4:'---',
          text5:'---',
          text6:'必填项',
        },
        {
          text1:'columnButton',
          text2:'表格操作栏按钮',
          text3:'Array',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'columnWidth',
          text2:'表格操作栏宽度',
          text3:'String',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'tableColWidth',
          text2:'表格列宽度',
          text3:'String',
          text4:'---',
          text5:'---',
          text6:'---',
        },
        {
          text1:'isHiddenSelection',
          text2:'是否隐藏勾选',
          text3:'Boolean',
          text4:'---',
          text5:'false',
          text6:'---',
        },
        {
          text1:'isHiddenIndex',
          text2:'是否隐藏序号',
          text3:'Boolean',
          text4:'---',
          text5:'false',
          text6:'---',
        },
        {
          text1:'isHiddenPage',
          text2:'是否隐藏分页',
          text3:'Boolean',
          text4:'---',
          text5:'false',
          text6:'---',
        },
        {
          text1:'total',
          text2:'表格数据总数',
          text3:'Number',
          text4:'---',
          text5:'0',
          text6:'必填项',
        },
        {
          text1:'pageSize',
          text2:'每页表格显示条数',
          text3:'Number',
          text4:'---',
          text5:'20',
          text6:'必填项',
        },
        {
          text1:'currentPage',
          text2:'当前页',
          text3:'Number',
          text4:'---',
          text5:'1',
          text6:'必填项',
        }
      ]
    }
  },
  methods: {
    // 表格分页回调
    getTableForm(page) {
      this.tableConfig.pageSize = page.pageSize;
      this.tableConfig.currentPage = page.pageNum;
      this.$message.success({
        message: "这是‘分页跳转’操作",
        showClose: true,
        duration: 1000,
      });
    },
    // 表格列点击回调
    getTableCol(data) {
      this.$message.success({
        message: "这是‘表格列点击’操作",
        showClose: true,
        duration: 1000,
      });

    }
  }
}
</script>

